 1	import * as React from 'react';
 2	import {
 3	  Dropdown,
 4	  DropdownItem,
 5	  DropdownList,
 6	  MenuToggle,
 7	  MenuToggleElement,
 8	} from '@patternfly/react-core';
 9	import { map } from 'lodash';
10	import { useTranslation } from 'react-i18next';
11	import { useFlag } from '@openshift-console/dynamic-plugin-sdk';
12	import { formatPrometheusDuration, parsePrometheusDuration } from './dateTime';
13	import { TimeRangeOptions, TimeRangeOptionsK8s } from './utils';
14	import { FLAG_PIPELINE_TEKTON_RESULT_INSTALLED } from '../../consts';
15	
16	interface TimeRangeDropdownProps {
17	  timespan: number;
18	  setTimespan: (t: number) => void;
19	}
20	
21	const TimeRangeDropdown: React.FC<TimeRangeDropdownProps> = ({
22	  timespan,
23	  setTimespan,
24	}) => {
25	  const [isOpen, setValue] = React.useState(false);
26	  const toggleIsOpen = React.useCallback(() => setValue((v) => !v), []);
27	  const setClosed = React.useCallback(() => setValue(false), []);
28	  const onChange = React.useCallback(
29	    (v: string) => setTimespan(parsePrometheusDuration(v)),
30	    [setTimespan],
31	  );
32	  const { t } = useTranslation('plugin__pipelines-console-plugin');
33	  const isTektonResultEnabled = useFlag(FLAG_PIPELINE_TEKTON_RESULT_INSTALLED);
34	
35	  const timeRangeOptions = isTektonResultEnabled
36	    ? TimeRangeOptions()
37	    : TimeRangeOptionsK8s();
38	  return (
39	    <div className="form-group">
40	      <label>{t('Time Range')}</label>
41	      <div>
42	        <Dropdown
43	          className="pipeline-overview__variable-dropdown"
44	          isOpen={isOpen}
45	          onOpenChange={(isOpen: boolean) => setValue(isOpen)}
46	          toggle={(toggleRef: React.Ref<MenuToggleElement>) => (
47	            <MenuToggle ref={toggleRef} onClick={toggleIsOpen}>
48	              {timeRangeOptions[formatPrometheusDuration(timespan)]}
49	            </MenuToggle>
50	          )}
51	        >
52	          <DropdownList>
53	            {map(timeRangeOptions, (name, key) => (
54	              <DropdownItem
55	                component="button"
56	                key={key}
57	                onClick={() => {
58	                  onChange(key);
59	                  setClosed();
60	                }}
61	              >
62	                {name}
63	              </DropdownItem>
64	            ))}
65	          </DropdownList>
66	        </Dropdown>
67	      </div>
68	    </div>
69	  );
70	};
71	
72	export default TimeRangeDropdown;

